class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        MAXN = 10**5
        spf = [i for i in range(MAXN+1)]
        for i in range(2, int(MAXN**0.5) + 1):
            if spf[i] == i:
                for j in range(i*i, MAXN+1, i):
                    if spf[j] == j:
                        spf[j] = i
        prime_count = [0] * (MAXN + 1)
        for num in nums:
            while num > 1:
                prime = spf[num]
                prime_count[prime] += 1
                num //= prime
        prefix_sum = [0]
        for count in prime_count[1:]:
            prefix_sum.append(prefix_sum[-1] + (1 if count > 0 else 0))
        results = []
        for idx, val in queries:
            old_val = nums[idx]
            nums[idx] = val
            while old_val > 1:
                prime = spf[old_val]
                prime_count[prime] -= 1
                if prime_count[prime] == 0:
                    prefix_sum[prime] = prefix_sum[prime-1]
                old_val //= prime
            while val > 1:
                prime = spf[val]
                prime_count[prime] += 1
                if prime_count[prime] == 1:
                    prefix_sum[prime] = prefix_sum[prime-1] + 1
                val //= prime
            results.append(prefix_sum[-1] - 1 if prefix_sum[-1] > 0 else 0)
        return results
